from dataclasses import dataclass
from enum import Enum

class Action(Enum):
    ALLOW = "allow"
    DENY = "deny"

class Protocol(Enum):
    TCP = "tcp"
    UDP = "udp"
    ICMP = "icmp"

@dataclass
class Packet:
    src_ip: str
    dst_ip: str
    src_port: int
    dst_port: int
    protocol: Protocol

@dataclass
class FirewallRule:
    action: Action
    src_ip: str  # Use '*' for any
    dst_ip: str  # Use '*' for any
    src_port: int  # Use 0 for any
    dst_port: int  # Use 0 for any
    protocol: Protocol

class PacketFilterFirewall:
    def __init__(self):
        self.rules = []

    def add_rule(self, rule: FirewallRule):
        self.rules.append(rule)

    def check_packet(self, packet: Packet) -> Action:
        for rule in self.rules:
            if self._matches(packet, rule):
                return rule.action
        return Action.DENY  # Default: deny

    def _matches(self, packet: Packet, rule: FirewallRule) -> bool:
        if rule.src_ip != '*' and rule.src_ip != packet.src_ip:
            return False
        if rule.dst_ip != '*' and rule.dst_ip != packet.dst_ip:
            return False
        if rule.src_port != 0 and rule.src_port != packet.src_port:
            return False
        if rule.dst_port != 0 and rule.dst_port != packet.dst_port:
            return False
        if rule.protocol != packet.protocol:
            return False
        return True

# Demo
firewall = PacketFilterFirewall()
firewall.add_rule(FirewallRule(Action.ALLOW, '*', '192.168.1.10', 0, 80, Protocol.TCP))
firewall.add_rule(FirewallRule(Action.ALLOW, '*', '192.168.1.10', 0, 443, Protocol.TCP))
firewall.add_rule(FirewallRule(Action.DENY, '*', '*', 0, 0, Protocol.ICMP))

test_packets = [
    Packet('10.0.0.5', '192.168.1.10', 5000, 80, Protocol.TCP),
    Packet('10.0.0.5', '192.168.1.10', 5000, 443, Protocol.TCP),
    Packet('10.0.0.5', '192.168.1.10', 5000, 22, Protocol.TCP),
    Packet('10.0.0.5', '192.168.1.5', 5000, 80, Protocol.TCP),
    Packet('10.0.0.5', '192.168.1.10', 5000, 0, Protocol.ICMP),
]

for pkt in test_packets:
    result = firewall.check_packet(pkt)
    print(f"Packet {pkt.src_ip}:{pkt.src_port} -> {pkt.dst_ip}:{pkt.dst_port}/{pkt.protocol.value} -> {result.value}")
